"use client";

import { useEffect, useState, useRef } from 'react';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Plus, MoreHorizontal, Loader2, Image as ImageIcon, X, Upload } from 'lucide-react';
import imageCompression from 'browser-image-compression';

export default function FeaturedPage() {
  const [works, setWorks] = useState<any[]>([]);
  const [artists, setArtists] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  
  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [openDropdownId, setOpenDropdownId] = useState<string | null>(null);

  // Form state
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    artist_id: '',
    display_order: '0',
    image_url: ''
  });
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    fetchWorks();
    fetchArtists();
  }, []);

  const fetchWorks = async () => {
    setLoading(true);
    const { data } = await supabase
      .from('featured_works')
      .select('*, artists(name)')
      .order('display_order', { ascending: true });
    if (data) setWorks(data);
    setLoading(false);
  };

  const fetchArtists = async () => {
    const { data } = await supabase
      .from('artists')
      .select('id, name')
      .order('name');
    if (data) setArtists(data);
  };

  const openNewModal = () => {
    setFormData({
      title: '', description: '', artist_id: '', display_order: '0', image_url: ''
    });
    setEditingId(null);
    setImageFile(null);
    setPreviewUrl(null);
    setIsModalOpen(true);
    setOpenDropdownId(null);
  };

  const openEditModal = (work: any) => {
    setFormData({
      title: work.title || '',
      description: work.description || '',
      artist_id: work.artist_id || '',
      display_order: work.display_order?.toString() || '0',
      image_url: work.image_url || ''
    });
    setEditingId(work.id);
    setImageFile(null);
    setPreviewUrl(work.image_url);
    setIsModalOpen(true);
    setOpenDropdownId(null);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Tem certeza que deseja excluir este destaque?')) return;
    setOpenDropdownId(null);
    
    const work = works.find(w => w.id === id);
    if (work?.image_url) {
      try {
        const url = new URL(work.image_url);
        const pathParts = url.pathname.split('/olympus/');
        if (pathParts.length > 1) {
          await supabase.storage.from('olympus').remove([pathParts[1]]);
        }
      } catch (e) {
        console.error("Failed to parse/delete image URL", e);
      }
    }

    await supabase.from('featured_works').delete().eq('id', id);
    fetchWorks();
  };

  const handleImageChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setImageFile(file);
    setPreviewUrl(URL.createObjectURL(file));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      let finalImageUrl = formData.image_url;

      if (imageFile) {
        const compressedFile = await imageCompression(imageFile, {
          maxSizeMB: 1,
          maxWidthOrHeight: 1920,
          useWebWorker: true
        });

        const fileExt = compressedFile.name.split('.').pop();
        const fileName = `${Math.random()}.${fileExt}`;
        const filePath = `featured/${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('olympus')
          .upload(filePath, compressedFile);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from('olympus')
          .getPublicUrl(filePath);

        finalImageUrl = publicUrl;
      }

      const payload = {
        ...formData,
        display_order: parseInt(formData.display_order, 10) || 0,
        artist_id: formData.artist_id || null,
        image_url: finalImageUrl
      };

      if (editingId) {
        await supabase.from('featured_works').update(payload).eq('id', editingId);
      } else {
        await supabase.from('featured_works').insert(payload);
      }

      setIsModalOpen(false);
      fetchWorks();
    } catch (error) {
      console.error('Error saving featured work:', error);
      alert('Erro ao salvar o destaque.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-8">
        <h1 className="font-serif text-3xl text-olympus-gold">Trabalhos em Destaque</h1>
        <Button className="gap-2" onClick={openNewModal}>
          <Plus size={18} />
          Novo Destaque
        </Button>
      </div>

      <div className="bg-olympus-graphite border border-olympus-gold/10 rounded-sm overflow-hidden min-h-[500px]">
        {loading ? (
          <div className="p-12 flex justify-center">
            <Loader2 className="animate-spin text-olympus-gold" size={24} />
          </div>
        ) : (
          <table className="w-full text-left text-sm">
            <thead className="bg-olympus-black/50 text-olympus-white/60 font-mono text-xs uppercase tracking-wider">
              <tr>
                <th className="p-4 font-normal">Ordem</th>
                <th className="p-4 font-normal">Destaque</th>
                <th className="p-4 font-normal">Artista</th>
                <th className="p-4 font-normal text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-olympus-gold/5">
              {works.map((work) => (
                <tr key={work.id} className="hover:bg-olympus-white/5 transition-colors group">
                  <td className="p-4 font-mono text-olympus-gold">{work.display_order}</td>
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="w-16 h-10 bg-olympus-black rounded-sm overflow-hidden border border-olympus-gold/20 flex items-center justify-center">
                        {work.image_url ? (
                          <img src={work.image_url} className="w-full h-full object-cover" alt="" />
                        ) : (
                          <ImageIcon size={16} className="text-olympus-white/20" />
                        )}
                      </div>
                      <span className="font-medium text-olympus-white truncate max-w-[200px]">{work.title}</span>
                    </div>
                  </td>
                  <td className="p-4 text-olympus-white/70">{work.artists?.name || 'N/A'}</td>
                  <td className="p-4 text-right relative">
                    <button 
                      onClick={() => setOpenDropdownId(openDropdownId === work.id ? null : work.id)}
                      className="text-olympus-white/40 hover:text-olympus-gold p-1 transition-colors"
                    >
                      <MoreHorizontal size={18} />
                    </button>
                    {openDropdownId === work.id && (
                      <div className="absolute right-4 mt-2 w-32 bg-olympus-graphite border border-olympus-gold/20 shadow-xl rounded-sm z-10 flex flex-col overflow-hidden">
                        <button onClick={() => openEditModal(work)} className="text-left px-4 py-2 text-sm hover:bg-olympus-gold/10 text-olympus-white">Editar</button>
                        <button onClick={() => handleDelete(work.id)} className="text-left px-4 py-2 text-sm hover:bg-olympus-wine/20 text-olympus-wine">Excluir</button>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
              {works.length === 0 && (
                <tr>
                  <td colSpan={4} className="p-8 text-center text-olympus-white/40">
                    Nenhum destaque cadastrado.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-olympus-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-olympus-graphite border border-olympus-gold/20 rounded-sm w-full max-w-xl max-h-[90vh] flex flex-col overflow-hidden">
            <div className="p-6 border-b border-olympus-gold/10 flex justify-between items-center bg-olympus-graphite z-10">
              <h2 className="font-serif text-2xl text-olympus-gold">{editingId ? 'Editar Destaque' : 'Novo Destaque'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-olympus-white/40 hover:text-olympus-white transition-colors">
                <X size={24} />
              </button>
            </div>
            
            <div className="overflow-y-auto flex-1 hide-scrollbar">
              <form onSubmit={handleSubmit} className="p-6 flex flex-col gap-6">
                <div>
                  <label className="block text-xs font-mono text-olympus-white/50 uppercase tracking-widest mb-2">Imagem</label>
                  <div 
                    className="border-2 border-dashed border-olympus-gold/20 rounded-sm h-48 flex flex-col items-center justify-center bg-olympus-black/50 hover:bg-olympus-black cursor-pointer transition-colors relative overflow-hidden"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    {previewUrl ? (
                      <img src={previewUrl} alt="Preview" className="w-full h-full object-contain" />
                    ) : (
                      <div className="flex flex-col items-center text-olympus-white/40">
                        <Upload size={32} className="mb-2" />
                        <span className="text-sm font-sans">Clique para enviar uma imagem</span>
                      </div>
                    )}
                    <input 
                      type="file" 
                      accept="image/*" 
                      className="hidden" 
                      ref={fileInputRef}
                      onChange={handleImageChange}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-mono text-olympus-white/50 uppercase tracking-widest mb-2">Título</label>
                  <input required type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full bg-olympus-black border border-olympus-gold/20 rounded-sm px-4 py-2 text-olympus-white focus:outline-none focus:border-olympus-gold" />
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="block text-xs font-mono text-olympus-white/50 uppercase tracking-widest mb-2">Artista</label>
                    <select value={formData.artist_id} onChange={e => setFormData({...formData, artist_id: e.target.value})} className="w-full bg-olympus-black border border-olympus-gold/20 rounded-sm px-4 py-2 text-olympus-white focus:outline-none focus:border-olympus-gold">
                      <option value="">Selecione...</option>
                      {artists.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-mono text-olympus-white/50 uppercase tracking-widest mb-2">Ordem de Exibição</label>
                    <input type="number" value={formData.display_order} onChange={e => setFormData({...formData, display_order: e.target.value})} className="w-full bg-olympus-black border border-olympus-gold/20 rounded-sm px-4 py-2 text-olympus-white focus:outline-none focus:border-olympus-gold font-mono" />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-mono text-olympus-white/50 uppercase tracking-widest mb-2">Descrição</label>
                  <textarea rows={3} value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full bg-olympus-black border border-olympus-gold/20 rounded-sm px-4 py-2 text-olympus-white focus:outline-none focus:border-olympus-gold resize-none" />
                </div>
              </form>
            </div>

            <div className="p-6 border-t border-olympus-gold/10 bg-olympus-graphite z-10 flex justify-end gap-4">
              <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="border-olympus-gold/20 text-olympus-white hover:bg-olympus-white/5">
                Cancelar
              </Button>
              <Button onClick={handleSubmit} disabled={isSubmitting} className="bg-olympus-gold text-olympus-black hover:bg-olympus-white flex gap-2">
                {isSubmitting && <Loader2 size={16} className="animate-spin" />}
                {editingId ? 'Salvar Alterações' : 'Criar Destaque'}
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
